# NL ZEH.  Zaandam - Enkhuizen
#
let ze = path("d3.nl.zeh");

with detail = 3,
     railway = :first :double :cat:dc15 :pax
{
    # point.nl.Zaandam  nl.DHA

    with link = "line.nl.ZEH" {
        track(:single :station :casing,
                ze[:zaa.ye - 0.1dl, :zaa.ye] << 0.5md << 1ms << 0.5mt
            ..  ze[:zaa.xe, :zaa.xe + 0.1dl] << 0.5md >> 0.5mt
        );
        track(:single :station,
                ze[:zaa.ye - 0.1dl, :zaa.ye] >> 0.5md >> 1ms >> 0.5mt
            ..  ze[:zaa.xe, :zaa.xe + 0.1dl] >> 0.5md << 0.5mt
        );
        track(ze[:zaa.xe, :zab - 0.49sw]);
    }

    with link = "point.nl.Zaanbrug" {
        track(ze[:zab - 0.5sw, :zab + 0.5sw]);
        marker(:left :de.hp :removed, ze[:zab] << 0.5md);
    }

    with link = "line.nl.ZEH" {
        track(ze[:zab + 0.49sw, :zko - 0.49sw]);
    }

    with link = "point.nl.Zaandam-Kogerveld" {
        track(ze[:zko - 0.5sw, :zko + 0.5sw]);
        marker(:left :de.bf, ze[:zko] << 0.5md);
        slabel(:nw, ze[:zko] >> 0.5md, "Z. Kogerveld");
    }

    with link = "line.nl.ZEH" {
        track(ze[:zko + 0.49sw, :zko + 1.71km]);
        line_label(:left:s, ze[:zko + 1.7km] << 0.5md, (-0.2dt, 0dt), "ZEH");
        track(ze[:zko + 1.69km, :oza - 0.49sw]);
    }

    with link = "point.nl.Oostzaan" {
        track(ze[:oza - 0.5sw, :oza + 0.5sw]);
        marker(:right :de.bf :removed, ze[:oza] >> 0.5md);
        slabel(:right :removed, ze[:oza] >> 0.5md >> 1sh + (1dt, 2.5dt),
            "Oostzaan"
        );
    }

    with link = "line.nl.ZEH" {
        track(ze[:oza + 0.49sw, :pwe - 0.49sw]);
    }

    with link = "point.nl.Purmerend-Weidevenne" {
        track(ze[:pwe - 0.5sw, :pwe + 0.5sw]);
        marker(:right :de.hp, ze[:pwe] >> 0.5md);
        slabel(:right, ze[:pwe] >> 0.5md >> 1sh + (1.5dt, 2.3dt),
            "P. Weidevenne"
        );
    }

    with link = "line.nl.ZEH" {
        track(ze[:pwe + 0.49sw, :nka + 0.1dl]);
    }

    with link = "point.nl.Noordhollands-kanaal-Purmerend" {
        marker(:right :de.dkst, ze[:nka] >> 0.5md);
    }

    with link = "line.nl.ZEH" {
        track(ze[:nka - 0.1dl, :pur - 0.49sw]);
    }

    with link = "point.nl.Purmerend" {
        track(ze[:pur - 0.5sw, :pur + 0.5sw]);
        marker(:left :de.hp, ze[:pur] << 0.5md);
        marker(:left :de.exbf, ze[:pur] << 0.5md);
        slabel(:left, ze[:pur] << 0.5md << 1.4sh + (-1.4dt, 1dt), "Purmerend");
    }

    with link = "line.nl.ZEH" {
        track(ze[:pur + 0.49sw, :pov - 0.49sw]);
    }

    with link = "point.nl.Purmerend-Overwhere" {
        track(ze[:pov - 0.5sw, :pov + 0.5sw]);
        marker(:left :de.bf, ze[:pov] << 0.5md);
        slabel(:left, ze[:pov] << 0.5md << 1sh + (-1.5dt, -0.3dt),
            "P. Overwhere"
        );
    }

    with link = "line.nl.ZEH" {
        track(ze[:pov + 0.49sw, :kwa - 0.49sw]);
    }

    with link = "point.nl.Kwadijk" {
        track(ze[:kwa - 0.5sw, :kwa + 0.5sw]);
        marker(:left :de.bf :removed, ze[:kwa] << 0.5md);
        slabel(:left :removed, ze[:kwa] << 0.5md << 1sh + (-1.5dt, 0.5dt),
            "Kwadijk"
        );
    }

    with link = "line.nl.ZEH" {
        track(ze[:kwa + 0.49sw, :kwa + 2.01km]);
        line_label(:right:w, ze[:kwa + 2km] >> 0.5md, "ZEH");
        track(ze[:kwa + 1.99km, :mid - 0.49sw]);
    }

    with link = "point.nl.Middelie" {
        track(ze[:mid - 0.5sw, :mid + 0.5sw]);
        marker(:left :de.hp :removed, ze[:mid] << 0.5md);
        slabel(:left :removed, ze[:mid] << 0.5md << 1sh + (-1.3dt, 1dt),
            "Middelie"
        );
    }

    with link = "line.nl.ZEH" {
        track(ze[:mid + 0.49sw, :ohu - 0.49sw]);
    }

    with link = "point.nl.Oosthuizen" {
        track(ze[:ohu - 0.5sw, :ohu + 0.5sw]);
        marker(:left :de.bf :removed, ze[:ohu] << 0.5md);
        slabel(:left :removed, ze[:ohu] << 0.5md << 1sh + (-1.3dt, 1dt),
            "Oosthuizen"
        );
    }

    with link = "line.nl.ZEH" {
        track(ze[:ohu + 0.49sw, :sar - 0.49sw]);
    }

    with link = "point.nl.Schardam" {
        track(ze[:sar - 0.5sw, :sar + 0.5sw]);
        marker(:right :de.hp :removed, ze[:sar] >> 0.5md);
        slabel(:right :removed, ze[:sar] >> 0.5md >> 1sh + (1.3dt, 1.2dt),
            "Schardam"
        );
    }

    with link = "line.nl.ZEH" {
        track(ze[:sar + 0.49sw, :ave - 0.49sw]);
    }

    with link = "point.nl.Avenhorn" {
        track(ze[:ave - 0.5sw, :ave + 0.5sw]);
        marker(:left :de.bf :removed, ze[:ave] << 0.5md);
        slabel(:left :removed, ze[:ave] << 0.5md << 1sh + (-1.3dt, 1dt),
            "Avenhorn"
        );
    }

    with link = "line.nl.ZEH" {
        track(ze[:ave + 0.49sw, :ave + 2.01km]);
        line_label(:left:e, ze[:ave + 2km] << 0.5md, (0dt, -0.3dt), "ZEH");
        track(ze[:ave + 1.99km, :hoa - 0.49seg]);
        track(:lor, ze[:hoa - 0.5seg, :hoa]);
        track(:lor, ze[:hoa, :hoo - 199m]);
    }

    with link = "point.nl.Hoorn-aansl", railway = :single {
        marker(:right :de.abzw, ze[:hoa] >> 0.5md);
    }

    with link = "point.nl.Hoorn", railway = :single {
        # NL HMB
        track(:nocat :museum,
                ze[:hoo - 65m, :hoo + 290m - 1dl] << 0.5md << 2ms << 1.5mt
            --  ze[:hoo + 290m, :hoo + 330m] << 0.5md << 1ms << 0.5mt
        );

        # NL HHH
        track(
                ze[:hoo - 200m, :hoo + 290m - 2dl] << 0.5md << 1ms << 0.5mt
            --  ze[:hoo + 290m - 1dl, :hoo + 290m - 0.9dl] << 0.5md >> 0.5mt
        );

        # NL ZEH
        track(:double, ze[:hoo - 200m, :hoo + 330m]);

        marker(:right :de.bf, ze[:hoo] >> 0.5md);
        slabel(:bottom :bold, ze[:hoo] >> 0.5md >> 1sh + (-0.5dt, 0.5dt),
            "Hoorn"
        );
    }

    with link = "line.nl.ZEH" {
        track(:lor, ze[:hoo + 329m, :hoo.ym]);
        track(:lor, ze[:hoo.ym, :hoo.ym + 0.5seg]);
        track(ze[:hoo.ym + 0.49seg, :hke - 0.49sw]);
    }

    with link = "point.nl.Hoorn-Kersenboogerd" {
        track(ze[:hke - 0.5sw, :hke + 450m]);
        marker(:right :de.bf, ze[:hke] >> 0.5md);
        slabel(:right, ze[:hke] >> 0.5md >> 1sh + (1.5dt, 1.8dt),
            "Hoorn Kersenboogerd"
        );
    }
}

with detail = 3,
     railway = :first :cat:dc15 :pax
{
    with link = "line.nl.ZEH" {
        track(ze[:hke + 449m, :blo - 0.49sw] >> 0.5md << 0.5mt);
    }

    with link = "point.nl.Blokker" {
        track(ze[:blo - 0.5sw, :blo + 0.5sw] >> 0.5md << 0.5mt);
        marker(:left :de.hp :removed, ze[:blo] >> 0.5md << 1mt);
        slabel(:left :removed, ze[:blo] >> 0.5md << 1md << 1sh + (-1dt, 1dt),
            "Blokker"
        );
    }

    with link = "line.nl.ZEH" {
        track(
                ze[:blo + 0.49sw, :hke.yw] >> 0.5md << 0.5mt
            ..  ze[:hke.xw + 2mt, :wwo - 0.49sw]
        );
    }

    with link = "point.nl.Westwoud" {
        track(ze[:wwo - 0.5sw, :wwo + 0.5sw]);
        marker(:left :de.bf :removed, ze[:wwo] << 0.5mt);
        slabel(:left :removed, ze[:wwo] >> 0.5mt << 1sh + (-1.8dt, -0.5dt),
            "Westwoud"
        );
    }

    with link = "line.nl.ZEH" {
        track(ze[:wwo + 0.49sw, :wwo + 1.01km]);
        line_label(:right:nw, ze[:wwo + 1km] >> 0.5mt, "ZEH");
        track(ze[:wwo + 0.99km, :hok - 0.49sw]);
    }

    with link = "point.nl.Hoogkarspel" {
        track(ze[:hok - 0.5sw, :hok + 0.5sw]);
        marker(:left :de.bf, ze[:hok] << 0.5mt);
        slabel(:left, ze[:hok] << 0.5mt << 1sh + (-1.8dt, -0.3dt),
            "Hoogkarspel"
        );
    }

    with link = "line.nl.ZEH" {
        track(ze[:hok + 0.49sw, :lut - 0.49sw]);
    }

    with link = "point.nl.Lutjebroek" {
        track(ze[:lut - 0.5sw, :lut + 0.5sw]);
        marker(:right :de.hp :removed, ze[:lut] >> 0.5mt);
        slabel(:bottom :removed, ze[:lut] >> 0.5mt >> 1sh + (2dt, 0.3dt),
            "Lutjebroek*"
        );
    }

    with link = "line.nl.ZEH" {
        track(ze[:lut + 0.49sw, :bog - 0.49sw]);
    }

    with link = "point.nl.Bovenkarspel-Grootebroek" {
        track(ze[:bog - 0.5sw, :bog + 0.5sw]);
        marker(:left :de.bf, ze[:bog] << 0.5mt);
        slabel(:left, ze[:bog] << 0.5mt << 1sh + (4dt, -0.8dt),
            vbox(:right:base, "Bovenkarspel-", "Grootebroek ")
        );
    }

    with link = "line.nl.ZEH" {
        track(ze[:bog + 0.49sw, :bof - 0.49sw]);
    }

    with link = "point.nl.Bovenkarspel-Flora" {
        track(ze[:bof - 0.5sw, :bof + 0.5sw]);
        marker(:left :de.hp, ze[:bof] << 0.5mt);
        slabel(:nw, ze[:bof] >> 0.5mt + (-0.5dt, 0dt),
            vbox(:left:top, "Bovenkarspel", "Flora*")
        );
    }

    with link = "line.nl.ZEH" {
        track(ze[:bof + 0.49sw, :enk.f - 0.49sw]);
    }

    with link = "point.nl.Enkhuizen" {
        track(ze[:enk.f - 0.5sw, :enk.f]);
        marker(:top :de.bf, ze[:enk.f]);
        slabel(:right :bold, ze[:enk.f] + (1sh, 0dt) + (1.3dt, 0.8dt),
            "Enkhuizen"
        );
    }
}

